+
+    /// Drift report for non-existent generation returns error.
+    #[test]
+    fn drift_report_nonexistent_generation(_dummy in 0..1u8) {
+        let (store, _dir) = open_store();
+        let result = store.drift_report("p-no", "g-no", "lex-v1", Some(100));
